#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define PI 3.1415926535897932
#define M 2147483647
#define A 1103515245
#define C 12345

double roundDouble(double value) {
    int newValue = (int)(value);
    if (value - newValue < 0.5)
        return (double)newValue;
    else
        return (double)(newValue + 1);
}

double randu(int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs((double)seed[index] / (double)M);
}

double randn(int *seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2.0 * PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

int findIndex_bin(double *CDF, int beginIndex, int endIndex, double value) {
    if (beginIndex > endIndex)
        return -1;

    int middleIndex = beginIndex + ((endIndex - beginIndex) / 2);

    if (value <= CDF[middleIndex]) {
        if (middleIndex == 0)
            return middleIndex;
        else if (value > CDF[middleIndex - 1])
            return middleIndex;
        else if (value == CDF[middleIndex - 1]) {
            while (middleIndex > 0 && CDF[middleIndex - 1] == value)
                middleIndex--;
            return middleIndex;
        }
    }

    if (value < CDF[middleIndex])
        return findIndex_bin(CDF, beginIndex, middleIndex + 1, value);
    return findIndex_bin(CDF, middleIndex - 1, endIndex, value);
}

kernel void likelihood_kernel(global double *arrayX, global double *arrayY, 
                              global double *xj, global double *yj,
                              global double *CDF, global int *ind, 
                              global int *objxy, global double *likelihood,
                              global unsigned char *I, global double *u,
                              global double *weights, const int Nparticles, 
                              const int countOnes, const int max_size, 
                              const int k, const int IszY, const int Nfr,
                              global int *seed, global double *partial_sums) {
    int x = get_global_id(0);

    if (x < Nparticles) {
        // Update positions
        arrayX[x] += 1.0 + 5.0 * randn(seed, x);
        arrayY[x] += -2.0 + 2.0 * randn(seed, x);

        // Calculate indices
        for (int y = 0; y < countOnes; y++) {
            int indX = (int)roundDouble(arrayX[x]) + objxy[y * 2 + 1];
            int indY = (int)roundDouble(arrayY[x]) + objxy[y * 2];
            int idx = indX * IszY * Nfr + indY * Nfr + k;
            if (idx >= max_size || idx < 0)
                idx = 0;
            ind[x * countOnes + y] = idx;
        }

        // Calculate likelihood
        double sum = 0.0;
        for (int y = 0; y < countOnes; y++) {
            int idx = ind[x * countOnes + y];
            double val = (double)I[idx];
            sum += ((pow(val - 100.0, 2.0) - pow(val - 228.0, 2.0)) / 50.0);
        }
        likelihood[x] = sum / (double)countOnes;

        // Apply exponential weight
        weights[x] = weights[x] * exp(likelihood[x]);

        // Store for sum
        partial_sums[x + 1] = weights[x];
    }

    // Compute cumulative sum and normalize (only on first thread)
    if (x == 0) {
        partial_sums[0] = 0.0;
        for (int i = 1; i <= Nparticles; i++) {
            partial_sums[i] += partial_sums[i - 1];
        }

        double sumWeights = partial_sums[Nparticles];
        for (int i = 0; i < Nparticles; i++) {
            weights[i] = weights[i] / sumWeights;
            if (i == 0)
                CDF[i] = weights[i];
            else
                CDF[i] = weights[i] + CDF[i - 1];
        }

        double u1 = (1.0 / (double)Nparticles) * randu(seed, 0);
        for (int i = 0; i < Nparticles; i++) {
            u[i] = u1 + (double)i / (double)Nparticles;
        }
    }
}

kernel void sum_kernel(global double *partial_sums, const int Nparticles) {
    // This kernel is logically merged into likelihood_kernel in this implementation
    // to ensure atomicity of the particle filter step per frame.
    // If called separately, it does nothing as the work is done in likelihood_kernel.
}

kernel void normalize_weights_kernel(global double *weights, const int Nparticles, 
                                     global double *partial_sums, global double *CDF, 
                                     global double *u, global int *seed) {
    // This kernel is logically merged into likelihood_kernel in this implementation.
    // If called separately, it does nothing as the work is done in likelihood_kernel.
}

kernel void find_index_kernel(global double *arrayX, global double *arrayY, 
                              global double *CDF, global double *u, 
                              global double *xj, global double *yj, 
                              global double *weights, const int Nparticles) {
    int j = get_global_id(0);

    if (j < Nparticles) {
        int i = findIndex_bin(CDF, 0, Nparticles - 1, u[j]);
        if (i == -1)
            i = Nparticles - 1;

        xj[j] = arrayX[i];
        yj[j] = arrayY[i];

        arrayX[j] = xj[j];
        arrayY[j] = yj[j];
        weights[j] = 1.0 / (double)Nparticles;
    }
}

